import numpy as np
import matplotlib.pyplot as plt

# Load the csv data generated by my C++ program
data = np.loadtxt('heat_results.csv', delimiter=',')

# Create the heatmap plot
plt.figure(figsize=(8, 6))
plt.imshow(data, cmap='hot', origin='lower', extent=[0, 10, 0, 10])
plt.colorbar(label='Temperature (°C)')

# Add labels and titles
plt.title('Transient Heat Diffusion in Copper Plate (10 Mins)')
plt.xlabel('X Coordinate (cm)')
plt.ylabel('Y Coordinate (cm)')

# Display the graphical window
plt.show()